 1	import * as React from 'react';
 2	import { useODFNamespaceSelector } from '@odf/core/redux';
 3	import { getStorageClusterInNs } from '@odf/core/utils';
 4	import {
 5	  StorageClusterKind,
 6	  StorageClusterModel,
 7	  useCustomTranslation,
 8	} from '@odf/shared';
 9	import { OverviewDetailItem as DetailItem } from '@odf/shared/overview-page';
10	import { referenceForModel } from '@odf/shared/utils';
11	import { useK8sWatchResource } from '@openshift-console/dynamic-plugin-sdk';
12	import {
13	  Card,
14	  CardHeader,
15	  CardTitle,
16	  CardBody,
17	  DescriptionList,
18	} from '@patternfly/react-core';
19	
20	const storageClusterResource = {
21	  kind: referenceForModel(StorageClusterModel),
22	  isList: true,
23	};
24	
25	const AutomaticBackupCard: React.FC = () => {
26	  const { t } = useCustomTranslation();
27	  const { odfNamespace } = useODFNamespaceSelector();
28	  const [ocsData, ocsLoaded, ocsError] = useK8sWatchResource<
29	    StorageClusterKind[]
30	  >(storageClusterResource);
31	
32	  const storageCluster: StorageClusterKind = getStorageClusterInNs(
33	    ocsData,
34	    odfNamespace
35	  );
36	  const dbBackup = storageCluster?.spec?.multiCloudGateway?.dbBackup;
37	
38	  return (
39	    <Card className="odf-overview-card--gradient">
40	      <CardHeader>
41	        <CardTitle>{t('Automatic backup')}</CardTitle>
42	      </CardHeader>
43	      <CardBody>
44	        {!!dbBackup ? (
45	          <DescriptionList>
46	            <DetailItem
47	              key="backupFrequency"
48	              title={t('Backup frequency')}
49	              isLoading={!ocsLoaded}
50	              error={ocsError}
51	            >
52	              {dbBackup.schedule}
53	            </DetailItem>
54	
55	            <DetailItem
56	              key="backupCopies"
57	              title={t('Number of backups to be retained')}
58	              isLoading={!ocsLoaded}
59	              error={ocsError}
60	            >
61	              {dbBackup.volumeSnapshot?.maxSnapshots}
62	            </DetailItem>
63	          </DescriptionList>
64	        ) : (
65	          <div className="text-secondary">{t('No automatic backup found')}</div>
66	        )}
67	      </CardBody>
68	    </Card>
69	  );
70	};
71	
72	export default AutomaticBackupCard;

